  }
  ?mammal wdt:P279 * wd:Q7377 ; wdt:P30 ?continent ; wdt:P2067 ?massQuantity .
  ?massQuantity wikibase:quantityValue ?weightNumeric .
  OPTIONAL {
    ?continent rdfs:label ?continentLabel
    filter(lang(?continentLabel) = "en")
    .
  }
  OPTIONAL {
    ?mammal rdfs:label ?mammalLabel
    filter(lang(?mammalLabel) = "en")
    .
  }
  {
    SELECT ?continent(MAX(?weightNumeric) AS ?maxWeight) WHERE {
      VALUES ?continent {
        wd:Q15 wd:Q48 wd:Q46 wd:Q49 wd:Q18 wd:Q51 wd:Q308
      }
      ?mammal wdt:P279 * wd:Q7377 ; wdt:P30 ?continent ; wdt:P2067 ?massQuantity .
      ?massQuantity wikibase:quantityValue ?weightNumeric .
    }
    GROUP BY ?continent
  }
  FILTER(?weightNumeric = ?maxWeight)
}
ORDER BY ?continent

