  VALUES ?series {
    wd:Q3511178 wd:Q14870260 wd:Q56692089
  }
  ?series wdt:P527 ?game .
  ?game wdt:P1109 ?attendance .
  FILTER(isNumeric(?attendance))
}
ORDER BY ASC(?attendance)
OFFSET 2
LIMIT 1

SELECT ?club(COUNT(?final) AS ?count) WHERE {
  VALUES ?club {
    wd:Q3044572 wd:Q249679
  }
  ?final wdt:P31 wd:Q2759594 .
  ?final wdt:P710 ?club .
}
GROUP BY ?club

SELECT ?attendance WHERE {
  VALUES(?home ?away) {(wd:Q334634 wd:Q650840)(wd:Q650840 wd:Q334634)
  }
  ?game wdt:P1995 ?home ; wdt:P1996 ?away ; wdt:P1110 ?attendance .
  BIND(xsd:integer(REPLACE(STR(?attendance) , "[^0-9]" , "")) AS ?attNum)
  FILTER(?attNum > 0)
}
ORDER BY DESC(?attNum)
LIMIT 1
OFFSET 2

SELECT ?attendance WHERE {
  VALUES ?series {
    wd:Q3511262 wd:Q3511261
  }
  ?series wdt:P527 ?game .
  ?game wdt:P1110 ?attendance .
  FILTER(CONTAINS(?attendance , '56000'))
}
ORDER BY DESC(xsd:integer(REPLACE(STR(?attendance) , ',' , '')))
LIMIT 1

SELECT ?attendance WHERE {
  VALUES ?team {
    wd:Q213959 wd:Q207841
  }
  .
  ?game wdt:P710 ?team ; wdt:P1110 ?attendance ; wdt:P580 ?date ; wdt:P31 wd:Q13406554 .
  FILTER(?date >= "2013-10-12" ^^ xsd:date && ?date <= "2013-10-19" ^^ xsd:date)
}
GROUP BY ?attendance
HAVING(COUNT(DISTINCT ?team) = 2)
ORDER BY ASC(xsd:integer(?attendance))
LIMIT 3

SELECT ?races ?year WHERE {
  VALUES ?year {
    2008 2015 2017 2018 2019
  }
  ?season wdt:P31 wd:Q137604 .
  ?season wdt:P1346 wd:Q9673 .
  ?season wdt:P1534 ?races .
  ?season wdt:P580 ?startTime .
  FILTER(YEAR(?startTime) = ?year)
}
ORDER BY DESC(?races)
LIMIT 1
OFFSET 2

SELECT ?attendance WHERE {
  VALUES ?series {
    wd:Q56692089 wd:Q14870260 wd:Q3511178
  }
  ?series p:P276 / pq:P1110 ?attendance .
}
ORDER BY DESC(xsd:integer(?attendance))
LIMIT 1

SELECT ?game ?attendance WHERE {
  ?series wdt:P361 wd:Q1363275 .
  ?series wdt:P585 ?date .
  FILTER(YEAR(?date) >= 1970 && YEAR(?date) <= 1979)
  {
    ?series wdt:P1346 wd:Q653772 ; wdt:P1451 wd:Q826751
  } UNION {
    ?series wdt:P1346 wd:Q826751 ; wdt:P1451 wd:Q653772
  }
  ?game wdt:P361 ?series .
  ?game(wdt:P1129 | wdt:P4989) ?attendance .
}
ORDER BY DESC(xsd:integer(?attendance))
LIMIT 1

SELECT ?club ?appearances WHERE {
  VALUES ?club {
    wd:Q3044572 wd:Q2272176 wd:Q2521385
  }
  OPTIONAL {
    ?club wdt:P1273 ?wins
  }
  OPTIONAL {
    ?club wdt:P1114 ?losses
  }
  BIND((COALESCE(?wins , 0) + COALESCE(?losses , 0)) AS ?appearances)
  FILTER(?appearances > 0)
}
ORDER BY ASC(?appearances)
LIMIT 2
OFFSET 1

SELECT ?duration_minutes WHERE {
  VALUES ?dodgers {
    wd:Q334634
  }
  VALUES ?phillies {
    wd:Q650840
  }
  ?series wdt:P31 wd:Q1363275 ; wdt:P710 ?dodgers ; wdt:P710 ?phillies ; wdt:P527 ?game .
  ?game wdt:P2047 ?duration_seconds .
  FILTER(ISNUMERIC(?duration_seconds))
  BIND(?duration_seconds / 60 AS ?duration_minutes)
}
ORDER BY ?duration_seconds
OFFSET 4
LIMIT 1

SELECT ?team(COUNT(?event) AS ?count) WHERE {
  VALUES ?team {
    wd:Q249679 wd:Q2521385 wd:Q2272176
  }
  ?event wdt:P1344 ?team .
  ?event rdfs:label ?label .
  FILTER(LANG(?label) = 'en' && CONTAINS(LCASE(?label) , 'grand final'))
}
GROUP BY ?team
ORDER BY ASC(?count)
LIMIT 1
OFFSET 1

SELECT ?club ?clubLabel(COUNT(DISTINCT ?season) AS ?count) WHERE {
  VALUES ?club {
    wd:Q2521385 wd:Q249679 wd:Q2272176
  }
  ?club p:P166 ?stmt .
  ?stmt ps:P166 wd:Q2637699 .
  OPTIONAL {
    ?club rdfs:label ?clubLabel
    FILTER(lang(?clubLabel) = 'en')
  }
}
GROUP BY ?club ?clubLabel
ORDER BY DESC(?count)
LIMIT 1
